// components/PropertyMap.js
import React, { useState, useCallback } from 'react';
import { GoogleMap, LoadScript, Marker, InfoWindow } from '@react-google-maps/api';

const PropertyMap = () => {
  const [properties, setProperties] = useState([]);
  const [selectedProperty, setSelectedProperty] = useState(null);
  const [center, setCenter] = useState({ lat: 10.7769, lng: 106.7009 }); // HCM City

  const mapContainerStyle = {
    width: '100%',
    height: '500px'
  };

  // Fetch properties for map
  const fetchProperties = async (bounds) => {
    try {
      const response = await fetch(
        `http://localhost:5001/api/properties/map${bounds ? `?bounds=${JSON.stringify(bounds)}` : ''}`
      );
      const data = await response.json();
      if (data.success) {
        setProperties(data.data);
      }
    } catch (error) {
      console.error('Error fetching properties:', error);
    }
  };

  // Fetch nearby properties
  const fetchNearby = async (lat, lng, radius = 10) => {
    try {
      const response = await fetch(
        `http://localhost:5001/api/properties/location?lat=${lat}&lng=${lng}&radius=${radius}`
      );
      const data = await response.json();
      if (data.success) {
        setProperties(data.data.map(p => ({
          id: p.id,
          position: { lat: parseFloat(p.latitude), lng: parseFloat(p.longitude) },
          title: p.title,
          price: p.price,
          address: p.address,
          distance: p.distance
        })));
      }
    } catch (error) {
      console.error('Error fetching nearby:', error);
    }
  };

  // Handle map load
  const onLoad = useCallback((map) => {
    fetchProperties();
  }, []);

  // Handle bounds change
  const onBoundsChanged = useCallback((map) => {
    if (map) {
      const bounds = map.getBounds();
      if (bounds) {
        fetchProperties({
          north: bounds.getNorthEast().lat(),
          south: bounds.getSouthWest().lat(),
          east: bounds.getNorthEast().lng(),
          west: bounds.getSouthWest().lng()
        });
      }
    }
  }, []);

  // Format price
  const formatPrice = (price) => {
    return new Intl.NumberFormat('vi-VN', {
      style: 'currency',
      currency: 'VND'
    }).format(price);
  };

  return (
    <LoadScript googleMapsApiKey={process.env.REACT_APP_GOOGLE_MAPS_API_KEY}>
      <GoogleMap
        mapContainerStyle={mapContainerStyle}
        center={center}
        zoom={12}
        onLoad={onLoad}
        onDragEnd={onBoundsChanged}
        onZoomChanged={onBoundsChanged}
      >
        {properties.map((property) => (
          <Marker
            key={property.id}
            position={property.position}
            title={property.title}
            onClick={() => setSelectedProperty(property)}
          />
        ))}

        {selectedProperty && (
          <InfoWindow
            position={selectedProperty.position}
            onCloseClick={() => setSelectedProperty(null)}
          >
            <div style={{ maxWidth: '200px' }}>
              <h3 style={{ margin: '0 0 8px' }}>{selectedProperty.title}</h3>
              <p style={{ margin: '0 0 4px', fontWeight: 'bold', color: '#e53935' }}>
                {formatPrice(selectedProperty.price)}
              </p>
              <p style={{ margin: '0', fontSize: '12px', color: '#666' }}>
                {selectedProperty.address}
              </p>
              {selectedProperty.distance && (
                <p style={{ margin: '4px 0 0', fontSize: '12px', color: '#1976d2' }}>
                  📍 {selectedProperty.distance.toFixed(2)} km away
                </p>
              )}
              <a 
                href={`/property/${selectedProperty.id}`}
                style={{ color: '#1976d2', fontSize: '12px' }}
              >
                View Details →
              </a>
            </div>
          </InfoWindow>
        )}
      </GoogleMap>
    </LoadScript>
  );
};

export default PropertyMap;
